  '2026-06-07 09:00:00',
  '[{"id":"complaints","icon":"📄","value":6,"labelAm":"ԿԸՀ ներկայացված գրավոր բողոք"},{"id":"resolved","icon":"🛠","value":46,"labelAm":"Տեղում վերացված դեպքեր"},{"id":"calls","icon":"☎️","value":24,"labelAm":"Հեռախոսային հաղորդում ՏԸՀ/ԿԸՀ"}]'::jsonb,
  '{"am":{"badge":"ՄԻՋԱՆԿՅԱԼ ԱՄՓՈՓՈՒՄ","title":"Ընտրական գործընթացի մշտադիտարկում","intro":"«Համայնքի երիտասարդներ» ՀԿ-ի կողմից իրականացվող «Դիտակետ» դիտորդական առաքելությունը շարունակում է ընտրական գործընթացի մշտադիտարկումը Հայաստանի տարբեր համայնքներում։ Ստորև՝ ժամը 13:00-ի դրությամբ միջանկյալ ամփոփումը։","highlight":"Շարունակվում է ընտրողների մասնակցության տվյալների հավաքագրումն ու ամփոփումը։","issues":["Քվեարկության գաղտնիության ապահովման հետ կապված թերություններ (ոչ ամբողջությամբ փակված պատուհաններ, քվեախցիկների կառուցվածքային խնդիրներ, բաց քվեարկության դեպքեր)","Վստահված անձանց կողմից ընտրական հանձնաժողովների գործառույթների փաստացի ստանձնում, ընտրողների ուղղորդում և ընտրական գործընթացին միջամտելու հնարավոր դրսևորումներ","Միևնույն քաղաքական ուժից մի քանի վստահված անձանց ներկայության վերաբերյալ ահազանգեր","Քարոզչության հնարավոր դրսևորումներ ընտրատեղամասերում և դրանց հարակից տարածքներում","Ընտրողների հոսքերի կազմակերպման, կուտակումների և ընթացակարգային խախտումների վերաբերյալ հաղորդումներ","Ընտրողների կողմից քվեաթերթիկների, ծրարների և քվեարկության կարգի խախտման առանձին դեպքեր","Զինծառայողների քվեարկության, ընտրողների նույնականացման և ընտրական ցուցակների հետ կապված առանձին ահազանգեր","Տեղամասային հանձնաժողովների աշխատանքների կազմակերպման և արձանագրման կարգի հետ կապված խնդիրներ"],"cases":[{"stations":"33/23, 29/54","text":"Արձանագրվել են դեպքեր, երբ վստահված անձինք ուղղորդել են ընտրողներին և կատարել հանձնաժողովի անդամներին վերապահված գործառույթներ։"},{"stations":"25/28","text":"Արձանագրվել է բաց քվեարկության դեպք, որի վերաբերյալ առկա են տեսաձայնագրություններ։"},{"stations":"32/15","text":"Հարակից տարածքում արձանագրվել է անձի ներկայություն, որը ներկայացել է որպես վստահված անձ, սակայն չի եղել գրանցված և չի կրել համապատասխան տարբերանշան։"},{"text":"Արձանագրվել են նաև ընտրողների կամարտահայտության գաղտնիության, քվեաթերթիկների հետ վարվելու կարգի և ընտրական գործընթացի կազմակերպման հետ կապված այլ դեպքեր։"}],"nextNote":"Հաջորդ հրապարակման մեջ կներկայացնենք առավել նշանակալի դեպքերի առանձին իրավական գնահատականը, բողոքարկման ընթացքը, ինչպես նաև արձանագրված խախտումների վերաբերյալ մանրամասն վերլուծությունը՝ պահպանելով անկախ, օբյեկտիվ և քննադատական մոտեցումը։","hashtags":["Դիտակետ","Ընտրություններ2026","ԸնտրականԴիտարկում","Ժողովրդավարություն"]}}'::jsonb
);
